{
  "grammar": [
    {
      "pattern": "可以 + [verb] + [object] + 嗎？",
      "structure": ["可以", "verb", "object", "嗎"],
      "explanation_en": "Use '可以' to ask for permission or to request something politely. It's a standard polite form in Taiwan.",
      "title": "Polite Request with 可以",
      "meaning": "Can I...? / May I...?",
      "when_to_use": ["When ordering food or drinks at a café", "When asking for an item in a shop", "When requesting a service"],
      "when_not_to_use": ["When making a direct command (use 請 instead)", "When talking to close friends (can be too formal)"],
      "pragmatic_notes": "In Taiwan, using 可以 is very common and polite. It's softer than just stating what you want.",
      "word_order_notes": "可以 comes before the verb. The object follows the verb. 嗎 ends the question.",
      "english_contrast": "English uses 'Can I...' or 'May I...' at the beginning. Chinese uses 可以 before the verb.",
      "korean_contrast": "Korean uses '~을/를 주세요' or '~해도 될까요?' which is similar to 可以...嗎.",
      "negative_examples": [
        {
          "text": "可以嗎？",
          "error": "Missing verb and object; incomplete request."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以我喝咖啡嗎？",
          "error": "Word order: 可以 must come before the verb, not before the subject."
        }
      ],
      "transformation_drills": ["Change '可以喝咖啡嗎？' to '可以喝茶嗎？'", "Change '可以看菜單嗎？' to '可以看書嗎？'"],
      "production_drills": ["Ask for a cup of water using 可以", "Ask to sit here using 可以"],
      "common_error_patterns": ["Placing 可以 after the subject", "Forgetting 嗎 at the end"],
      "repair_feedback": {
        "word_order": "Put 可以 before the verb, not before the subject.",
        "politeness": "Using 可以 is polite; avoid direct commands.",
        "vocabulary": "Use appropriate objects like 咖啡, 茶, 水."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express what you want in a polite, non-demanding way. It's softer than '要'.",
      "title": "Expressing Wants with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When telling a shop assistant what you want", "When making a polite request"],
      "when_not_to_use": ["When you need to be very direct (use 要 instead)", "When asking for permission (use 可以 instead)"],
      "pragmatic_notes": "In Taiwan, 想要 is very common in cafés and shops. It sounds friendly and polite.",
      "word_order_notes": "想要 is followed directly by the object. No verb needed if the object is a noun.",
      "english_contrast": "English uses 'I would like' or 'I want'. Chinese uses 想要 + object.",
      "korean_contrast": "Korean uses '~을/를 원하다' or '~을/를 주세요' which is similar to 想要.",
      "negative_examples": [
        {
          "text": "想要嗎？",
          "error": "Missing object; incomplete expression."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想要喝咖啡嗎？",
          "error": "Using 嗎 with 想要 is incorrect; 想要 is a statement, not a question."
        }
      ],
      "transformation_drills": ["Change '想要咖啡' to '想要茶'", "Change '想要水' to '想要牛奶'"],
      "production_drills": ["Say you want a small latte", "Say you want iced tea"],
      "common_error_patterns": ["Adding 嗎 after 想要", "Using 想要 with a verb unnecessarily"],
      "repair_feedback": {
        "word_order": "Place 想要 before the object.",
        "politeness": "想要 is polite; avoid using 要 directly.",
        "vocabulary": "Use nouns like 拿鐵, 紅茶, 綠茶."
      }
    },
    {
      "pattern": "不好意思 + [request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' as a polite softener before making a request. It shows politeness and consideration.",
      "title": "Polite Softener 不好意思",
      "meaning": "Excuse me / Sorry to bother you",
      "when_to_use": ["When starting a request in a café or shop", "When you need to get someone's attention", "When you want to be extra polite"],
      "when_not_to_use": ["When you are apologizing for a mistake (use 對不起 instead)", "When talking to close friends (can be too formal)"],
      "pragmatic_notes": "In Taiwan, 不好意思 is very common and polite. It's used to soften requests and show respect.",
      "word_order_notes": "不好意思 comes at the beginning of the sentence, before the request.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry to bother you' at the beginning. Chinese uses 不好意思.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' which is similar to 不好意思.",
      "negative_examples": [
        {
          "text": "不好意思嗎？",
          "error": "Using 嗎 with 不好意思 is incorrect; it's a phrase, not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我不好意思要咖啡。",
          "error": "不好意思 should be at the beginning, not as part of the verb phrase."
        }
      ],
      "transformation_drills": ["Add 不好意思 before '可以看菜單嗎？'", "Add 不好意思 before '想要一杯水'"],
      "production_drills": ["Politely ask for a menu using 不好意思", "Politely ask for the price using 不好意思"],
      "common_error_patterns": ["Using 不好意思 in the middle of a sentence", "Confusing 不好意思 with 對不起"],
      "repair_feedback": {
        "word_order": "Place 不好意思 at the beginning of the request.",
        "politeness": "Using 不好意思 makes the request more polite.",
        "vocabulary": "Use 不好意思 before requests, not apologies."
      }
    }
  ]
}
